#include <bits/stdc++.h>
using namespace std;
string l;
int a[8];
int main(){
    cin>>l;
    for(int i=0;i<l.size();i++){
        if(l[i]=='b')a[1]++;
        else if(l[i]=='o')a[2]++;
        else if(l[i]=='y')a[3]++;
        else if(l[i]=='g')a[4]++;
        else if(l[i]=='i')a[5]++;
        else if(l[i]=='r')a[6]++;
        else if(l[i]=='l')a[7]++;
    }
    cout<<min(a[1],min(a[2],a[3]))<<endl<<min(min(a[4],a[5]),min(a[6],a[7]));
    return 0;
}
